/* Button Utils, By BlackStar, Ver.0.1.0 */
(()=>{"use strict";const getRadioBtnName=text=>"radiobutton-"+text.toString().replace(/['"]/g,"").replace(/^[$_]/,"").trim();Macro.add("redo_radio",{handler(){const parts=this.args.raw.split(" ");const entity=this;$(document).on(":passagedisplay",(function(){for(const part of parts){const btnName=getRadioBtnName(part);$(`input[name='${btnName}']`).change((()=>{const failRE=/^(?:do|for)$/;const passRE=/^(?:button|link(?:append|prepend|replace)?)$/;const closest=entity.contextFind((ctx=>failRE.test(ctx.name)||passRE.test(ctx.name)));if(closest&&failRE.test(closest.name)){return entity.error(`must not be used directly within macro <<${closest.name}>>`)}triggerEvent(":redo",document,{detail:{btnName:btnName}})}))}}))}})})();
/* End Button Utils */